import { useState } from 'react';
import { Card, Stack, Row, Text, Spacer } from '@ggui-ai/design/primitives';

interface WeatherForecastDay {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: WeatherForecastDay[];
}

// Helper function to get emoji based on condition
function getWeatherEmoji(condition: string): string {
  const lowerCondition = (condition || '').toLowerCase();
  if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
  if (lowerCondition.includes('cloudy') || lowerCondition.includes('overcast')) return '☁️';
  if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) return '🌧️';
  if (lowerCondition.includes('snowy') || lowerCondition.includes('snow')) return '❄️';
  if (lowerCondition.includes('stormy') || lowerCondition.includes('thunder')) return '⛈️';
  if (lowerCondition.includes('windy')) return '💨';
  if (lowerCondition.includes('foggy') || lowerCondition.includes('fog')) return '🌫️';
  return '🌤️'; // Default fallback
}

function getDayLabel(day: string | undefined, index: number): string {
  if (day) return day;
  const dayNumber = index + 1;
  return 'Day ' + dayNumber;
}

export default function GeneratedComponent({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 65,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '☁️', high: 68, low: 58 },
    { day: 'Wed', icon: '🌧️', high: 65, low: 55 },
    { day: 'Thu', icon: '☀️', high: 70, low: 60 },
    { day: 'Fri', icon: '☀️', high: 76, low: 63 },
  ],
}: Props) {
  const weatherEmoji = getWeatherEmoji(condition);
  const tempUnit = unit || 'F';

  return (
    <div
      style={{
        backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        padding: 'var(--ggui-spacing-6, 24px)',
        minHeight: '100vh',
      }}
    >
      <div style={{ maxWidth: '600px', margin: '0 auto' }}>
        {/* Main Weather Card */}
        <Card shadow="md" padding="24">
          <Stack direction="vertical" gap={24}>
            {/* Header with City */}
            <div>
              <Text
                variant="h2"
                color="var(--ggui-color-onSurface, #18181b)"
                weight="bold"
              >
                {city}
              </Text>
            </div>

            {/* Current Temperature Section */}
            <Stack direction="vertical" gap={16} align="center">
              {/* Weather Icon and Condition */}
              <Stack direction="horizontal" gap={12} align="center" justify="center">
                <div
                  style={{
                    fontSize: '64px',
                    lineHeight: '1',
                    display: 'flex',
                    alignItems: 'center',
                  }}
                >
                  {weatherEmoji}
                </div>
                <div>
                  <Text
                    variant="h3"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    weight="medium"
                  >
                    {condition}
                  </Text>
                </div>
              </Stack>

              {/* Large Temperature Display */}
              <div style={{ textAlign: 'center' }}>
                <Text
                  variant="h1"
                  color="var(--ggui-color-primary-600, #0284c7)"
                  weight="bold"
                  style={{
                    fontSize: 'var(--ggui-font-size-4xl, 36px)',
                    lineHeight: '1.1',
                  }}
                >
                  {temperature}°{tempUnit}
                </Text>
              </div>
            </Stack>

            {/* Divider */}
            <div
              style={{
                height: '1px',
                backgroundColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            />

            {/* Current Conditions Details */}
            <Stack direction="horizontal" gap={24} justify="between">
              {/* Humidity */}
              <Stack direction="vertical" gap={8} align="center">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  Humidity
                </Text>
                <Text
                  variant="h3"
                  color="var(--ggui-color-onSurface, #18181b)"
                  weight="semibold"
                >
                  {humidity}%
                </Text>
              </Stack>

              {/* Wind Speed */}
              <Stack direction="vertical" gap={8} align="center">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  Wind Speed
                </Text>
                <Text
                  variant="h3"
                  color="var(--ggui-color-onSurface, #18181b)"
                  weight="semibold"
                >
                  {windSpeed} mph
                </Text>
              </Stack>
            </Stack>

            {/* Divider */}
            <div
              style={{
                height: '1px',
                backgroundColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            />

            {/* 5-Day Forecast */}
            <Stack direction="vertical" gap={12}>
              <Text
                variant="label"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                weight="semibold"
              >
                5-Day Forecast
              </Text>

              {/* Forecast Strip */}
              <Row gap={8} wrap>
                {forecast.map((day, index) => {
                  const displayDay = getDayLabel(day.day, index);
                  const displayIcon = day.icon || '🌤️';
                  const displayHigh = day.high ?? '--';
                  const displayLow = day.low ?? '--';

                  return (
                    <div
                      key={index}
                      style={{
                        flex: '1 1 calc(20% - 8px)',
                        minWidth: '80px',
                        padding: 'var(--ggui-spacing-3, 12px)',
                        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        textAlign: 'center',
                        border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                        transition: 'all 200ms ease-out',
                        cursor: 'default',
                      }}
                      onMouseEnter={(e) => {
                        (e.currentTarget as HTMLElement).style.backgroundColor =
                          'var(--ggui-color-primary-50, #f0f9ff)';
                        (e.currentTarget as HTMLElement).style.borderColor =
                          'var(--ggui-color-primary-200, #bae6fd)';
                      }}
                      onMouseLeave={(e) => {
                        (e.currentTarget as HTMLElement).style.backgroundColor =
                          'var(--ggui-color-surfaceVariant, #f4f4f5)';
                        (e.currentTarget as HTMLElement).style.borderColor =
                          'var(--ggui-color-outlineVariant, #e4e4e7)';
                      }}
                    >
                      {/* Day Name */}
                      <Text
                        variant="label"
                        color="var(--ggui-color-onSurface, #18181b)"
                        weight="medium"
                        style={{ display: 'block', marginBottom: '4px' }}
                      >
                        {displayDay}
                      </Text>

                      {/* Weather Icon */}
                      <div
                        style={{
                          fontSize: '28px',
                          lineHeight: '1',
                          textAlign: 'center',
                          marginBottom: '6px',
                        }}
                      >
                        {displayIcon}
                      </div>

                      {/* High/Low Temps */}
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        style={{ display: 'block', marginBottom: '2px' }}
                      >
                        <span style={{ fontWeight: 'var(--ggui-font-weight-semibold, 600)' }}>
                          {displayHigh}°
                        </span>
                      </Text>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {displayLow}°
                      </Text>
                    </div>
                  );
                })}
              </Row>
            </Stack>
          </Stack>
        </Card>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { Container, Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface StreamEvent {
  type: string;
  symbol?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks?: Stock[];
}

/**
 * Stock Ticker Dashboard Component
 * 
 * Displays live market data with real-time price updates
 * 
 * __GGUI_STREAM_SPEC__
 * {
 *   "events": {
 *     "price-update": {
 *       "schema": {
 *         "type": "object",
 *         "properties": {
 *           "type": { "type": "string", "const": "price-update" },
 *           "symbol": { "type": "string" },
 *           "price": { "type": "number" },
 *           "change": { "type": "number" },
 *           "changePercent": { "type": "number" }
 *         },
 *         "required": ["type", "symbol"]
 *       },
 *       "description": "Live price update for a single stock"
 *     }
 *   }
 * }
 * __GGUI_STREAM_SPEC_END__
 */
export default function StockTickerDashboard({ stocks = [] }: Props) {
  const [stockData, setStockData] = useState<Stock[]>(stocks);
  const [lastUpdated, setLastUpdated] = useState<string>(new Date().toLocaleTimeString());
  const [currentTime, setCurrentTime] = useState<string>(new Date().toLocaleTimeString());
  const updateHandlerRef = useRef<((event: StreamEvent) => void) | null>(null);

  // Update clock every second
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentTime(new Date().toLocaleTimeString());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  // Set up stream event handler via ref
  useEffect(() => {
    updateHandlerRef.current = (event: StreamEvent) => {
      if (event.type === 'price-update' && event.symbol) {
        const { symbol, price, change, changePercent } = event;
        setStockData((prevData) =>
          prevData.map((stock) =>
            stock.symbol === symbol
              ? { ...stock, price, change, changePercent }
              : stock
          )
        );
        setLastUpdated(new Date().toLocaleTimeString());
      }
    };

    // Expose handler for ggui:agent-data event binding
    (globalThis as any).__ggui_price_update = updateHandlerRef.current;

    return () => {
      delete (globalThis as any).__ggui_price_update;
    };
  }, []);

  // Update stock data when initial props change
  useEffect(() => {
    setStockData(stocks);
    if (stocks.length > 0) {
      setLastUpdated(new Date().toLocaleTimeString());
    }
  }, [stocks]);

  const getChangeColor = (changePercent?: number): string => {
    if (changePercent === undefined || changePercent === null) {
      return 'var(--ggui-color-onSurface)';
    }
    return changePercent >= 0
      ? 'var(--ggui-color-success-600)'
      : 'var(--ggui-color-error-600)';
  };

  const getChangeBgColor = (changePercent?: number): string => {
    if (changePercent === undefined || changePercent === null) {
      return 'transparent';
    }
    return changePercent >= 0
      ? 'var(--ggui-color-success-50, #f0fdf4)'
      : 'var(--ggui-color-error-50, #fef2f2)';
  };

  const formatPrice = (price?: number): string => {
    if (price === undefined || price === null) {
      return '0.00';
    }
    return price.toFixed(2);
  };

  const formatChange = (change?: number): string => {
    if (change === undefined || change === null) {
      return '0.00';
    }
    return change.toFixed(2);
  };

  const formatPercent = (percent?: number): string => {
    if (percent === undefined || percent === null) {
      return '0.00';
    }
    return percent.toFixed(2);
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack direction="vertical" gap={24}>
        {/* Header */}
        <Row justify="between" align="center">
          <Text variant="h1" weight="bold" style={{ color: 'var(--ggui-color-onSurface)' }}>
            Market Watch
          </Text>
          <Text variant="body" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
            {currentTime}
          </Text>
        </Row>

        {/* Stock Cards Grid */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-4)',
          }}
        >
          {stockData.map((stock) => {
            const changePercent = stock.changePercent;
            const changeColor = getChangeColor(changePercent);
            const changeBgColor = getChangeBgColor(changePercent);
            const priceStr = formatPrice(stock.price);
            const changeStr = formatChange(stock.change);
            const percentStr = formatPercent(changePercent);
            const prefix = stock.change && stock.change >= 0 ? '+' : '';
            const percentPrefix = changePercent && changePercent >= 0 ? '+' : '';

            return (
              <Card
                key={stock.symbol}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                style={{
                  backgroundColor: 'var(--ggui-color-surfaceVariant)',
                  borderRadius: 'var(--ggui-shape-radius-lg)',
                  transition: 'all 200ms ease-out',
                }}
              >
                <Stack direction="vertical" gap={12}>
                  {/* Ticker Symbol */}
                  <Text
                    variant="h2"
                    weight="bold"
                    style={{ color: 'var(--ggui-color-onSurface)' }}
                  >
                    {stock.symbol || 'N/A'}
                  </Text>

                  {/* Company Name */}
                  <Text
                    variant="body"
                    style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}
                  >
                    {stock.name || 'Company Name'}
                  </Text>

                  {/* Current Price */}
                  <div style={{ marginTop: 'var(--ggui-spacing-2)' }}>
                    <Text
                      variant="h3"
                      weight="semibold"
                      style={{ color: 'var(--ggui-color-primary-600)' }}
                    >
                      {'$' + priceStr}
                    </Text>
                  </div>

                  {/* Change and Change Percent */}
                  <Row gap={12}>
                    <div
                      style={{
                        backgroundColor: changeBgColor,
                        padding: 'var(--ggui-spacing-2) var(--ggui-spacing-4)',
                        borderRadius: 'var(--ggui-shape-radius-md)',
                        display: 'flex',
                        alignItems: 'center',
                        gap: 'var(--ggui-spacing-2)',
                      }}
                    >
                      <Text
                        variant="label"
                        weight="semibold"
                        style={{ color: changeColor }}
                      >
                        {prefix + changeStr}
                      </Text>
                      <Text
                        variant="label"
                        weight="semibold"
                        style={{ color: changeColor }}
                      >
                        {'(' + percentPrefix + percentStr + '%' + ')'}
                      </Text>
                    </div>
                  </Row>
                </Stack>
              </Card>
            );
          })}
        </div>

        {/* Last Updated Footer */}
        <div
          style={{
            display: 'flex',
            justifyContent: 'flex-end',
            paddingTop: 'var(--ggui-spacing-4)',
            borderTop: '1px solid var(--ggui-color-outline)',
          }}
        >
          <Text
            variant="caption"
            style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}
          >
            {'Last Updated: ' + lastUpdated}
          </Text>
        </div>
      </Stack>
    </Container>
  );
}

import { useState } from 'react';
import { Container, Card, Stack, Row, Text, Input, Select, Button, Checkbox, Divider, Icon } from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: Record<string, unknown>;
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string }) => void;
}

interface OnboardingData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

export default function GeneratedComponent({
  initialProfile = {},
  avatarOptions = ['😊', '🤓', '🎨', '🚀'],
  roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
  onComplete = () => {},
}: Props) {
  const [currentStep, setCurrentStep] = useState(0);
  const [data, setData] = useState<OnboardingData>({
    name: (initialProfile as any)?.name || '',
    email: (initialProfile as any)?.email || '',
    avatar: (initialProfile as any)?.avatar || avatarOptions[0],
    role: (initialProfile as any)?.role || '',
    emailNotifications: (initialProfile as any)?.emailNotifications ?? true,
    theme: (initialProfile as any)?.theme || 'light',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const steps = ['Profile Setup', 'Preferences', 'Review & Confirm'];

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const validateStep = (step: number): boolean => {
    const newErrors: Record<string, string> = {};
    if (step === 0) {
      if (!data.name.trim()) newErrors.name = 'Name is required';
      if (!data.email.trim()) newErrors.email = 'Email is required';
      else if (!validateEmail(data.email)) newErrors.email = 'Please enter a valid email address';
    }
    if (step === 1 && !data.role) newErrors.role = 'Role selection is required';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (validateStep(currentStep) && currentStep < steps.length - 1) setCurrentStep(currentStep + 1);
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1);
      setErrors({});
    }
  };

  const handleComplete = () => {
    onComplete(data);
  };

  const updateData = <K extends keyof OnboardingData>(key: K, value: OnboardingData[K]) => {
    setData((prev) => ({ ...prev, [key]: value }));
    if (errors[key]) setErrors((prev) => { const n = { ...prev }; delete n[key]; return n; });
  };

  const progressPercent = String(Math.round(((currentStep + 1) / steps.length) * 100)) + '%';

  return (
    <Container maxWidth="md" padding={32}>
      <Card padding={32} shadow="md" border>
        <Stack direction="vertical" gap={32}>
          <Stack direction="vertical" gap={12}>
            <Row justify="between" align="center">
              <Text variant="label" weight="semibold">Step {currentStep + 1} of {steps.length}</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{steps[currentStep]}</Text>
            </Row>
            <div style={{ width: '100%', height: 4, backgroundColor: 'var(--ggui-color-outline)', borderRadius: 'var(--ggui-shape-radius-full)', overflow: 'hidden' }}>
              <div style={{ height: '100%', width: progressPercent, backgroundColor: 'var(--ggui-color-primary-600)', transition: 'width 300ms ease-out' }} />
            </div>
          </Stack>

          <Divider />

          <div style={{ animation: 'fadeIn 300ms ease-out' }}>
            {currentStep === 0 && (
              <Stack direction="vertical" gap={20}>
                <Stack direction="vertical" gap={4}>
                  <Text variant="h3">Create Your Profile</Text>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">Let's start with the basics</Text>
                </Stack>
                <Stack direction="vertical" gap={8}>
                  <Input label="Full Name" placeholder="Enter your full name" value={data.name} onChange={(v) => updateData('name', v)} required error={errors.name} />
                </Stack>
                <Stack direction="vertical" gap={8}>
                  <Input label="Email Address" type="email" placeholder="you@example.com" value={data.email} onChange={(v) => updateData('email', v)} required error={errors.email} />
                </Stack>
                <Stack direction="vertical" gap={12}>
                  <Text variant="label" weight="semibold">Choose Your Avatar</Text>
                  <Row gap={12} wrap>
                    {avatarOptions.map((emoji) => (
                      <button key={emoji} onClick={() => updateData('avatar', emoji)} style={{ width: 56, height: 56, borderRadius: 'var(--ggui-shape-radius-md)', border: data.avatar === emoji ? '2px solid var(--ggui-color-primary-600)' : '2px solid var(--ggui-color-outline)', backgroundColor: data.avatar === emoji ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surfaceVariant)', fontSize: 28, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', transition: 'all 200ms ease-out' }}>
                        {emoji}
                      </button>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {currentStep === 1 && (
              <Stack direction="vertical" gap={20}>
                <Stack direction="vertical" gap={4}>
                  <Text variant="h3">Set Your Preferences</Text>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">Customize your experience</Text>
                </Stack>
                <Select label="Professional Role" value={data.role} onChange={(v) => updateData('role', v)} options={roleOptions.map((r) => ({ value: r, label: r }))} placeholder="Select your role" required error={errors.role} />
                <Divider />
                <Checkbox label="Email Notifications" checked={data.emailNotifications} onChange={(v) => updateData('emailNotifications', v)} description="Receive email updates about your activity and important announcements" />
                <Divider />
                <Stack direction="vertical" gap={12}>
                  <Text variant="label" weight="semibold">Theme Preference</Text>
                  <Row gap={12}>
                    <button onClick={() => updateData('theme', 'light')} style={{ flex: 1, padding: 'var(--ggui-spacing-4)', borderRadius: 'var(--ggui-shape-radius-md)', border: data.theme === 'light' ? '2px solid var(--ggui-color-primary-600)' : '2px solid var(--ggui-color-outline)', backgroundColor: data.theme === 'light' ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surfaceVariant)', cursor: 'pointer', textAlign: 'center', fontWeight: 500, fontSize: 'var(--ggui-font-size-sm)', transition: 'all 200ms ease-out' }}>☀️ Light</button>
                    <button onClick={() => updateData('theme', 'dark')} style={{ flex: 1, padding: 'var(--ggui-spacing-4)', borderRadius: 'var(--ggui-shape-radius-md)', border: data.theme === 'dark' ? '2px solid var(--ggui-color-primary-600)' : '2px solid var(--ggui-color-outline)', backgroundColor: data.theme === 'dark' ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surfaceVariant)', cursor: 'pointer', textAlign: 'center', fontWeight: 500, fontSize: 'var(--ggui-font-size-sm)', transition: 'all 200ms ease-out' }}>🌙 Dark</button>
                  </Row>
                </Stack>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack direction="vertical" gap={20}>
                <Stack direction="vertical" gap={4}>
                  <Text variant="h3">Review Your Setup</Text>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">Make sure everything looks good before completing</Text>
                </Stack>
                <Card padding={16} shadow="sm" border style={{ backgroundColor: 'var(--ggui-color-surfaceVariant)' }}>
                  <Stack direction="vertical" gap={16}>
                    <Stack direction="vertical" gap={8}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Profile</Text>
                      <Row gap={12} align="center">
                        <div style={{ fontSize: 32, width: 48, height: 48, display: 'flex', alignItems: 'center', justifyContent: 'center', borderRadius: 'var(--ggui-shape-radius-md)', backgroundColor: 'var(--ggui-color-primary-100)' }}>{data.avatar}</div>
                        <Stack direction="vertical" gap={2}>
                          <Text variant="body" weight="semibold">{data.name}</Text>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{data.email}</Text>
                        </Stack>
                      </Row>
                    </Stack>
                    <Divider />
                    <Stack direction="vertical" gap={8}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Preferences</Text>
                      <Stack direction="vertical" gap={6}>
                        <Row justify="between">
                          <Text variant="body">Role</Text>
                          <Text variant="body" weight="medium">{data.role}</Text>
                        </Row>
                        <Row justify="between">
                          <Text variant="body">Email Notifications</Text>
                          <Text variant="body" weight="medium" color={data.emailNotifications ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-onSurfaceVariant)'}>{data.emailNotifications ? '✓ Enabled' : '✗ Disabled'}</Text>
                        </Row>
                        <Row justify="between">
                          <Text variant="body">Theme</Text>
                          <Text variant="body" weight="medium">{data.theme === 'light' ? '☀️ Light' : '🌙 Dark'}</Text>
                        </Row>
                      </Stack>
                    </Stack>
                  </Stack>
                </Card>
              </Stack>
            )}
          </div>

          <Divider />

          <Row gap={12} justify={currentStep === 0 ? 'end' : 'between'}>
            {currentStep > 0 && <Button variant="outline" onClick={handleBack}>Go Back</Button>}
            {currentStep < steps.length - 1 ? (
              <Button variant="primary" onClick={handleNext}>
                Next
                <Icon name="chevron-right" size={16} />
              </Button>
            ) : (
              <Button variant="primary" onClick={handleComplete}>
                <Icon name="check" size={16} />
                Complete Setup
              </Button>
            )}
          </Row>
        </Stack>
      </Card>

      <style>{`@keyframes fadeIn { from { opacity: 0; transform: translateY(4px); } to { opacity: 1; transform: translateY(0); } }`}</style>
    </Container>
  );
}
